#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int Amin,Bmin,Cmin,Tmin,A,B,C;
        scanf("%d %d %d %d %d %d %d", &Amin,&Bmin,&Cmin,&Tmin,&A,&B,&C);
        if(A>=Amin && B>=Bmin && C>=Cmin && (A+B+C)>=Tmin)
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}

