#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        Amin = int(next(it)); Bmin = int(next(it)); Cmin = int(next(it)); Tmin = int(next(it))
        A = int(next(it)); B = int(next(it)); C = int(next(it))
        if A >= Amin and B >= Bmin and C >= Cmin and (A + B + C) >= Tmin:
            out.append("YES")
        else:
            out.append("NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

